#include <vector>
#include <queue>
#include <cstdint>
using namespace std;

typedef int64_t Int64;

Int64 solve(vector<vector<Int64>>& grid, Int64 k) {
    int m = grid.size();
    if (m == 0) 
        return 0;
    int n = grid[0].size();
    Int64 count = 0;
    vector<vector<int>> dirs = {{1,0}, {-1,0}, {0,1}, {0,-1}};

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] > 0) {
                Int64 total = 0;
                queue<pair<int, int>> q;
                q.push({i, j});
                total += grid[i][j];
                grid[i][j] = 0;

                while (!q.empty()) {
                    auto cell = q.front();
                    q.pop();
                    int x = cell.first;
                    int y = cell.second;

                    for (int d = 0; d < 4; d++) {
                        int nx = x + dirs[d][0];
                        int ny = y + dirs[d][1];
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0) {
                            total += grid[nx][ny];
                            grid[nx][ny] = 0;
                            q.push({nx, ny});
                        }
                    }
                }

                if (total % k == 0) {
                    count++;
                }
            }
        }
    }

    return count;
}
